// Get input
const input = items[0].json.content;

// ----------------------
// 1. Extract JSON block
// ----------------------
const match = input.match(/```json\s*([\s\S]*?)\s*```/);

if (!match) {
	return [{ json: { error: "No JSON block found" } }];
}

let rawJson = match[1];

// ----------------------
// 2. Clean JSON
// ----------------------
let cleaned = rawJson
	.replace(/,\s*}/g, '}')   // remove trailing commas
	.replace(/,\s*]/g, ']');

// ----------------------
// 3. FIX BRACKET IMBALANCE (IMPORTANT)
// ----------------------
let open = (cleaned.match(/{/g) || []).length;
let close = (cleaned.match(/}/g) || []).length;

// remove extra closing braces
while (close > open) {
	cleaned = cleaned.replace(/}\s*$/, '');
	close--;
}

// add missing closing braces
while (open > close) {
	cleaned += '}';
	close++;
}

// ----------------------
// 4. Parse safely
// ----------------------
let parsed;
try {
	parsed = JSON.parse(cleaned);
} catch (e) {
	// LAST fallback: return raw but still usable
	return [
		{
			json: {
				raw_text: input,
				note: "Could not fully parse JSON, returning raw text"
			}
		}
	];
}

// ----------------------
// 5. Normalize structure
// ----------------------
const sentiment = parsed.sentiment || {};
const compliance = parsed.compliance_flag || {};
const risk = parsed.risk_indicators || {};
const entities = parsed.key_entities || {};

// ----------------------
// 6. Final clean output
// ----------------------
const result = {
	post_type: parsed.post_type || null,
	language: parsed.language || null,
	intent: parsed.intent || null,

	sentiment_label: sentiment.label || null,
	sentiment_confidence: sentiment.confidence || null,
	sentiment_score: parsed.sentiment_score || null,

	category: parsed.category || null,
	topic: parsed.topic || null,
	severity_level: parsed.severity_level || null,

	risk_score: parsed.risk_score || null,

	compliance_flag: compliance.flagged ?? compliance ?? null,
	compliance_reason: compliance.reason || null,

	service_failure: risk.service_failure ?? null,
	regulatory_violation: risk.regulatory_violation ?? null,
	fraud_risk: risk.fraud_risk ?? null,
	reputational_damage: risk.reputational_damage ?? null,
	competitive_weakness: risk.competitive_weakness ?? null,

	// handle both array + object formats
	key_entities: Array.isArray(entities)
		? entities
		: [
			...(entities.banks || []),
			...(entities.products || []),
			...(entities.competitors || [])
		],

	summary: parsed.summary || null,
	recommended_action: parsed.recommended_action || null,
	escalation_required: parsed.escalation_required ?? null
};

// ----------------------
// 7. Return usable output
// ----------------------
return [
	{
		json: result
	}
];

