const rows = $input.all().map(i => i.json);

// --------------------
let total = rows.length;

let sentiment = { positive: 0, negative: 0, neutral: 0, scoreSum: 0 };
let risk = { fraud: 0, compliance: 0, competitive: 0 };
let severity = { High: 0, Medium: 0, Low: 0 };

const isTrue = (v) => v === true || v === "true" || v === "TRUE";

// --------------------
// Process Data
// --------------------
for (const r of rows) {
  const label = (r.sentiment_label || "").toLowerCase();

  if (label.includes("positive")) sentiment.positive++;
  else if (label.includes("negative")) sentiment.negative++;
  else sentiment.neutral++;

  sentiment.scoreSum += Number(r.sentiment_confidence || 0);

  if (isTrue(r.fraud_risk)) risk.fraud++;
  if (isTrue(r.compliance_flagged)) risk.compliance++;
  if (isTrue(r.competitive_weakness)) risk.competitive++;

  if (severity[r.severity_level] !== undefined) {
    severity[r.severity_level]++;
  }
}

// --------------------
// Metrics
// --------------------
const avgSentiment = total ? (sentiment.scoreSum / total).toFixed(2) : 0;

const percent = (val) => total ? Math.round((val / total) * 100) : 0;

// ✅ FIXED PIE CALCULATION
const riskTotal = risk.fraud + risk.compliance + risk.competitive;

const riskPercent = (val) => {
  return riskTotal ? Math.round((val / riskTotal) * 100) : 0;
};

// Pie style (handles zero case)
const pieStyle = riskTotal === 0
  ? "background:#ecf0f1"
  : `background: conic-gradient(
      #e74c3c 0% ${riskPercent(risk.fraud)}%,
      #f39c12 ${riskPercent(risk.fraud)}% ${riskPercent(risk.fraud) + riskPercent(risk.compliance)}%,
      #3498db ${riskPercent(risk.fraud) + riskPercent(risk.compliance)}% 100%
    )`;

const totalRisks = riskTotal;

