  padding: 15px;
  border-radius: 10px;
  text-align: center;
  border: 1px solid #ddd;
}

.kpi h2 {
  margin: 0;
  font-size: 22px;
}

.kpi p {
  margin: 5px 0 0;
  color: #7f8c8d;
}

/* Cards */
.card {
  background: white;
  border: 1px solid #ddd;
  padding: 15px;
  margin-bottom: 20px;
  border-radius: 10px;
}

/* Bars */
.row {
  margin-bottom: 12px;
}

.label {
  font-size: 13px;
  margin-bottom: 4px;
}

.bar-container {
  background: #ecf0f1;
  border-radius: 20px;
  overflow: hidden;
}

.bar {
  height: 18px;
  font-size: 11px;
  color: white;
  text-align: right;
  padding-right: 5px;
  line-height: 18px;
}

.green { background: #2ecc71; }
.red { background: #e74c3c; }
.orange { background: #f39c12; }
.gray { background: #95a5a6; }

/* Pie */
.pie {
  width: 140px;
  height: 140px;
  border-radius: 50%;
  margin: 10px auto;
}

.center { text-align: center; }

</style>
</head>

<body>

<h1>📊 Risk & Sentiment Dashboard</h1>

<!-- KPI -->
<div class="kpi-grid">
  <div class="kpi">
    <h2>${total}</h2>
    <p>Total Records</p>
  </div>

  <div class="kpi">
    <h2>${avgSentiment}</h2>
    <p>Avg Sentiment</p>
  </div>

  <div class="kpi">
    <h2>${totalRisks}</h2>
    <p>Total Risks</p>
  </div>
</div>

<!-- Risk -->
<div class="card center">
  <h2>⚠️ Risk Distribution</h2>

  <div class="pie" style="${pieStyle}"></div>

  <p>
    🔴 Fraud (${risk.fraud})<br>
    🟠 Compliance (${risk.compliance})<br>
    🔵 Competitive (${risk.competitive})
  </p>
